SELECT id, user_id, username, operation, method, params, ip, duration, status, error_msg, create_time
FROM sys_operation_log
WHERE id = #{id}

SELECT id, user_id, username, operation, method, params, ip, duration, status, error_msg, create_time FROM sys_operation_log
AND user_id = #{userId}
AND username LIKE CONCAT('%', #{username}, '%')
AND operation LIKE CONCAT('%', #{operation}, '%')
AND status = #{status}
ORDER BY create_time DESC

SELECT COUNT(1)
FROM sys_operation_log


        AND user_id = #{userId}


        AND username LIKE CONCAT('%', #{username}, '%')


        AND operation LIKE CONCAT('%', #{operation}, '%')


        AND status = #{status}
